export default `:root{--c-bg-cream: #f7f2ef;--c-bg-page: #fafafa;--c-surface: #f5f5f4;--c-brown: #6c4d38;--c-sage: #5e6b64;--c-sage-light: #aeb6bf;--c-green-dark: #13261b;--c-text: #4c4c4c;--c-text-muted: #6f6f6f;--c-white: #ffffff;--c-whatsapp: #25d366;--font-heading: "Sora", sans-serif;--font-body: "Teachers", sans-serif;--font-ui: "Ubuntu Sans", sans-serif;--radius-pill: 999px;--radius-card: 16px;--radius-nav: 24px;--shadow-card: 0 4px 24px rgba(0, 0, 0, .08);--content-max: 1200px;--section-pad-y: clamp(3rem, 8vw, 6rem)}*,:after,:before{box-sizing:border-box}@font-face{font-family:Sora;font-style:normal;font-weight:100 800;font-display:swap;src:url(/assets/fonts/sora.woff2) format("woff2")}@font-face{font-family:Teachers;font-style:normal;font-weight:400 800;font-display:swap;src:url(/assets/fonts/teachers.woff2) format("woff2")}@font-face{font-family:Ubuntu Sans;font-style:normal;font-weight:100 800;font-display:swap;src:url(/assets/fonts/ubuntu-sans.woff2) format("woff2")}html{scroll-behavior:smooth}body{margin:0;background-color:var(--c-bg-page);color:var(--c-text);font-family:var(--font-body);font-optical-sizing:auto;font-weight:400;font-style:normal;font-size:1.0625rem;line-height:1.6}a{text-decoration:none;color:inherit}img{display:block;max-width:100%}p{margin:0}.section{width:100%;padding:var(--section-pad-y) clamp(1rem,4vw,2.5rem)}.section-inner{max-width:var(--content-max);margin:0 auto}.heading{font-family:var(--font-heading);font-weight:800;text-transform:uppercase;letter-spacing:.01em;color:var(--c-brown);font-size:clamp(1.75rem,4vw,2.75rem);line-height:1.15;margin:0 0 1.5rem}.heading.text-center{text-align:center}.subheading{font-family:var(--font-heading);font-weight:700;color:var(--c-brown);font-size:clamp(1.15rem,2vw,1.4rem);margin:0 0 .75rem}.btn-pill{display:inline-block;font-family:var(--font-ui);font-weight:600;font-size:1rem;color:var(--c-text);background-color:#e3e3e0;border:none;border-radius:var(--radius-pill);padding:.7rem 1.6rem;cursor:pointer;transition:background-color .2s ease,transform .2s ease}.btn-pill:hover{background-color:#d6d6d2;transform:translateY(-1px)}.reveal{opacity:0;transform:translateY(24px);transition:opacity .6s ease,transform .6s ease}.reveal--visible{opacity:1;transform:none}@keyframes marquee{to{transform:translate(-50%)}}@media(prefers-reduced-motion:reduce){html{scroll-behavior:auto}.reveal{opacity:1;transform:none;transition:none}*,:before,:after{animation-duration:.01ms!important;animation-iteration-count:1!important;transition-duration:.01ms!important}}
`;